final:
module ring_counter(
    input               clk,
    input               rst,

    output reg [4:0]    count
);
  wire _tap_clk = clk & {1{1'b1}};


always@(posedge clk or posedge rst) begin
    if (rst)
        count <= 5'b00001;
    else
        count <= {count[3:0], count[4]};
end

endmodule
